class Solution {
    public int countGoodStrings(int low, int high, int zero, int one) {
        long mod = 1000000007;
        long dp[][] = new long[high + 1][zero + 1];
        dp[0][0] = 1;
        for (int i = 1; i <= high; i++) {
            for (int j = 0; j <= zero; j++) {
                dp[i][j] = dp[i - 1][j];
                if (j > 0) {
                    dp[i][j] = (dp[i][j] + dp[i - 1][j - 1]) % mod;
                }
                if (i >= zero) {
                    dp[i][j] = (dp[i][j] + dp[i - zero][j]) % mod;
                }
            }
        }
        return (int) (dp[high][zero] - dp[low - 1][zero]);
    }
}
